export function AppStateProvider({ children, initialState, onChangeAppState }: Props) {
  const hasAppStateContext = useContext(HasAppStateContext);
  if (hasAppStateContext) {
    throw new Error("AppStateProvider cannot be nested");
  }

  const [store] = useState(() => 
    createStore(initialState ?? getDefaultAppState(), onChangeAppState)
  );

  // 监听设置变化并同步到AppState
  const onSettingsChange = useEffectEvent((source: SettingSource) =>
    applySettingsChange(source, store.setState)
  );
  useSettingsChange(onSettingsChange);

  return (
    <HasAppStateContext.Provider value={true}>
      <AppStoreContext.Provider value={store}>
        <MailboxProvider>
          <VoiceProvider>{children}</VoiceProvider>
        </MailboxProvider>
      </AppStoreContext.Provider>
    </HasAppStateContext.Provider>
  );
}

export function useAppState<T>(selector: (state: AppState) => T): T {
  const store = useAppStore();

  const get = () => {
    const state = store.getState();
    const selected = selector(state);
    // 防止返回整个state的误用
    if (state === selected) {
      throw new Error(`Selector returned original state`);
    }
    return selected;
  };

  return useSyncExternalStore(store.subscribe, get, get);
}

const VoiceProvider: (props: { children: React.ReactNode }) => React.ReactNode = 
  feature('VOICE_MODE') 
    ? require('../context/voice.js').VoiceProvider 
    : ({ children }) => children;
